What does this program print?

```cpp
#include <iostream>
#include <string>
#include <string_view>

int main() {
    std::string s{ "hello" };
    std::string_view sv{ s };
    std::cout << sv.length() << '\n';
    std::cout << sv << '\n';
}
```

The code below is intended to print the word `"quick"`. What is wrong?

```cpp
#include <iostream>
#include <string>
#include <string_view>

std::string_view getWord() {
    std::string sentence{ "the quick brown fox" };
    return sentence.substr(4, 5);
}

int main() {
    std::string_view word{ getWord() };
    std::cout << word << '\n';
}
```

What does this program print?

```cpp
#include <iostream>
#include <string_view>

void printFirst(std::string_view sv) {
    std::cout << sv.substr(0, 3) << '\n';
}

int main() {
    printFirst("elephant");
    printFirst("ant");
}
```

